// Process Bark response - merge with original webhook input
// $input.all() provides both Bark API response and Webhook Trigger payload
const allInputs = $input.all();
const barkResponse = allInputs[0]?.json || {};
const webhookInput = allInputs[1]?.json || {};

const audio_base64 = barkResponse.audio_base64 || '';
const sample_rate = barkResponse.sample_rate || 0;
const format = barkResponse.format || 'wav';

return [{
  json: {
    success: !!audio_base64,
    format: format,
    sample_rate: sample_rate,
    audio_size_bytes: audio_base64.length,
    timestamp: new Date().toISOString(),
    channel: webhookInput.channel || '#general',
    text: webhookInput.text || '',
    voice_preset: webhookInput.voice_preset || 'v2/en_speaker_6',
    output_format: webhookInput.output_format || 'wav'
  }
}];
